import UIKit

class AppDelegate: UIResponder, UIApplicationDelegate {

    func application(_ app: UIApplication, open url: URL, options: [UIApplication.OpenURLOptionsKey : Any] = [:]) -> Bool {
        guard url.scheme == "https" && url.host == "myapp.com", let components = URLComponents(url: url, resolvingAgainstBaseURL: false), let queryItems = components.queryItems else {
